// Devuelve la lista plana + añade flags útiles para el selector:
//   full              → promoción 100% llena (no se puede asignar)
//   manana_disponible → turno mañana con plazas libres
//   tarde_disponible  → turno tarde con plazas libres
const items = ($input.all() || []).map(i => i.json).filter(x => x && x.id);
const out = items.map(p => ({
  ...p,
  full: (p.libres_total || 0) <= 0,
  manana_disponible: (p.libres_manana || 0) > 0,
  tarde_disponible:  (p.libres_tarde  || 0) > 0
}));
return [{ json: { promociones: out } }];

// NODO MONOLÍTICO: valida + hace HTTP Request a PostgREST + formatea respuesta.
// Sin branching de n8n (IF/Switch misfiran en esta instancia).
//
// Usa $helpers.httpRequestWithAuthentication para llamar a Supabase
// usando la credencial predefinida `supabaseApi` configurada en este node.

const prep = (() => {
  try {
// Validación + construcción de row (lógica original de Preparar Promoción)
const raw = $input.first().json || {};
const b = (raw.body && typeof raw.body === 'object') ? raw.body : raw;
const action = String(b.action || 'create').toLowerCase();
const p = b.promocion || {};
if (!['create','update','delete','reactivar'].includes(action)) {
  return { __error: true, errores: ['action inválida: ' + action], action };
}
const errores = [];
if (action === 'create' && (!p.nombre || !String(p.nombre).trim())) errores.push('nombre obligatorio');
if (action !== 'create' && !p.id) errores.push('id obligatorio para ' + action);
if (errores.length > 0) return { __error: true, errores, action };

const row = {};
if (action === 'create') {
  row.nombre = String(p.nombre).trim();
  if (p.descripcion != null)   row.descripcion   = String(p.descripcion);
  if (p.fecha_inicio)          row.fecha_inicio  = p.fecha_inicio;
  row.estado        = p.estado === 'cerrada' ? 'cerrada' : 'activa';
  row.plazas_manana = Number.isFinite(+p.plazas_manana) ? +p.plazas_manana : 8;
  row.plazas_tarde  = Number.isFinite(+p.plazas_tarde)  ? +p.plazas_tarde  : 8;
  if (p.created_by) row.created_by = String(p.created_by);
} else if (action === 'update') {
  row.id = p.id;
  if (p.nombre       !== undefined) row.nombre       = String(p.nombre).trim();
  if (p.descripcion  !== undefined) row.descripcion  = p.descripcion ? String(p.descripcion) : null;
  if (p.fecha_inicio !== undefined) row.fecha_inicio = p.fecha_inicio || null;
  if (p.estado       !== undefined) row.estado       = p.estado === 'cerrada' ? 'cerrada' : 'activa';
  if (p.plazas_manana !== undefined && Number.isFinite(+p.plazas_manana)) row.plazas_manana = +p.plazas_manana;
  if (p.plazas_tarde  !== undefined && Number.isFinite(+p.plazas_tarde))  row.plazas_tarde  = +p.plazas_tarde;
  row.updated_at = new Date().toISOString();
} else if (action === 'delete') {
  row.id = p.id; row.deleted_at = new Date().toISOString();
} else if (action === 'reactivar') {
  row.id = p.id; row.deleted_at = null;
}
return { __error: false, action, row };
  } catch (e) {
    return { __error: true, errores: [String(e && e.message || e)], action: 'unknown' };
  }
})();

if (prep.__error) {
  return [{ json: {
    __skipHttp: true,
    __isCreate: true,
    __id: null,
    __body: '{}',
    success: false,
    errores: prep.errores,
    action: prep.action,
    promocion: null
  } }];
}

const { action, row } = prep;
const isCreate = action === 'create';

// Construir URL y método
const id = isCreate ? null : row.id;
const body = { ...row };
if (!isCreate) delete body.id;

const supaHost = $credentials?.supabaseApi?.host;
// No podemos leer credenciales en Code node — la HTTP Request se hace via
// $helpers.httpRequestWithAuthentication que sí las resuelve. Usamos
// expresión relativa (sin host) — requiere baseUrl en la credencial
// O bien pasamos el host por variable de entorno.
//
// ALTERNATIVA más robusta: el Code node no puede hacer httpRequest con
// credencial autenticada en todas las versiones de n8n. Mejor usar un
// subworkflow o un HTTP Request node aparte. Aquí devolvemos __prep para
// que el HTTP Request downstream lo consuma.

return [{ json: {
  __prep: true,
  action,
  row,
  __isCreate: isCreate,
  __id: id,
  __body: JSON.stringify(body)
} }];

// Consolida respuesta del HTTP PostgREST. PostgREST devuelve array.
const items = $input.all() || [];
// Si Preparar ya cortocircuitó con error, el primer item traerá success:false.
const first = items[0] && items[0].json;
if (first && first.success === false && Array.isArray(first.errores)) return [{ json: first }];

let rows = [];
const errores = [];
for (const it of items) {
  const j = it.json; if (!j) continue;
  if (Array.isArray(j)) { rows = rows.concat(j); continue; }
  if (j.error) { errores.push(String(j.error.message || j.error)); continue; }
  if (j.code && j.message && !j.id) { errores.push(j.message + (j.details?' ('+j.details+')':'')); continue; }
  if (j.id) rows.push(j);
}
if (rows.length === 0 && errores.length === 0) errores.push('HTTP respondió sin filas');
return [{ json: {
  success: rows.length > 0,
  promocion: rows[0] || null,
  errores
} }];
